{
  "name": "JIRA Timesheet Summarizer",
  "description": "A professional tool to process JIRA timesheet CSV exports and generate a clean, project-member summary table with decimal hour conversions."
}

import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

export interface TimesheetRow {
  member: string;
  project: string;
  avatar?: string;
  dailyHours: Record<string, number>; // date string -> decimal hours
  totalHours: number;
}

export interface ParsedData {
  rows: TimesheetRow[];
  dates: string[];
}

import { TimesheetRow, ParsedData } from '../types';

/**
 * Converts JIRA time strings like "8h", "1h 30m", "30m" into decimal numbers.
 */
export const parseJiraTimeString = (timeStr: string): number => {
  if (!timeStr || timeStr === '0') return 0;

  const hourMatch = timeStr.match(/(\d+)h/);
  const minMatch = timeStr.match(/(\d+)m/);

  let hours = 0;
  if (hourMatch) {
    hours += parseInt(hourMatch[1], 10);
  }
  if (minMatch) {
    hours += parseInt(minMatch[1], 10) / 60;
  }

  // Handle case where it's just a number without units
  if (!hourMatch && !minMatch && !isNaN(parseFloat(timeStr))) {
    return parseFloat(timeStr);
  }

  return hours;
};

/**
 * Extracts project code from key (e.g., "UPDP-2" -> "UPDP")
 */
export const getProjectCode = (key: string): string => {
  if (!key) return 'Unknown';
  return key.split('-')[0];
};

/**
 * Parses the raw CSV string into an aggregated structure.
 */
export const parseTimesheetCsv = (csvText: string): ParsedData => {
  // Simple CSV parser that handles quotes
  const parseCSVLine = (text: string) => {
    const result = [];
    let cur = '';
    let inQuotes = false;
    for (let i = 0; i < text.length; i++) {
      const char = text[i];
      if (char === '"') {
        inQuotes = !inQuotes;
      } else if (char === ',' && !inQuotes) {
        result.push(cur.trim());
        cur = '';
      } else {
        cur += char;
      }
    }
    result.push(cur.trim());
    return result;
  };

  const lines = csvText.trim().split('\n');
  if (lines.length < 2) return { rows: [], dates: [] };

  const header = parseCSVLine(lines[0]);

  // Find column indices
  const authorIdx = header.indexOf('Worklog Author');
  const keyIdx = header.indexOf('Key');
  const avatarIdx = header.indexOf('Avatar');

  // Dates are usually between Avatar/Author and Key/Started
  // We'll identify them by matching the date format (e.g., "1-Dec-25")
  const datePattern = /^\d{1,2}-[A-Za-z]{3}-\d{2}$/;
  const dateIndices: number[] = [];
  const dateStrings: string[] = [];

  header.forEach((col, idx) => {
    if (datePattern.test(col)) {
      dateIndices.push(idx);
      dateStrings.push(col);
    }
  });

  // Aggregation map: member|project -> TimesheetRow
  const aggregation: Record<string, TimesheetRow> = {};

  for (let i = 1; i < lines.length; i++) {
    const row = parseCSVLine(lines[i]);
    if (row.length < header.length) continue;

    const memberName = row[authorIdx];
    const projectCode = getProjectCode(row[keyIdx]);
    const avatar = row[avatarIdx];
    const aggKey = `${memberName}|${projectCode}`;

    if (!aggregation[aggKey]) {
      aggregation[aggKey] = {
        member: memberName,
        project: projectCode,
        avatar,
        dailyHours: {},
        totalHours: 0
      };
    }

    dateIndices.forEach((colIdx, listIdx) => {
      const dateStr = dateStrings[listIdx];
      const decimalHours = parseJiraTimeString(row[colIdx]);

      if (decimalHours > 0) {
        aggregation[aggKey].dailyHours[dateStr] = (aggregation[aggKey].dailyHours[dateStr] || 0) + decimalHours;
        aggregation[aggKey].totalHours += decimalHours;
      }
    });
  }

  return {
    rows: Object.values(aggregation).sort((a, b) => a.member.localeCompare(b.member) || a.project.localeCompare(b.project)),
    dates: dateStrings
  };
};

import React from 'react';
import { ParsedData } from '../types';

interface Props {
  data: ParsedData;
}

const TimesheetTable: React.FC<Props> = ({ data }) => {
  if (data.rows.length === 0) {
    return (
      <div className="flex flex-col items-center justify-center p-12 bg-white rounded-xl border-2 border-dashed border-slate-200 text-slate-400">
        <p>No data to display. Please upload a JIRA CSV export.</p>
      </div>
    );
  }

  return (
    <div className="w-full overflow-x-auto bg-white rounded-xl shadow-sm border border-slate-200">
      <table className="w-full text-left border-collapse min-w-max">
        <thead>
          <tr className="bg-slate-50 border-b border-slate-200 sticky top-0 z-10">
            <th className="px-4 py-3 font-semibold text-slate-700 text-sm border-r border-slate-200 bg-slate-50 sticky left-0 z-20">Project</th>
            <th className="px-4 py-3 font-semibold text-slate-700 text-sm border-r border-slate-200 bg-slate-50 sticky left-[120px] md:left-[140px] z-20">Member</th>
            {data.dates.map((date) => (
              <th key={date} className="px-2 py-3 font-semibold text-slate-600 text-[10px] uppercase text-center border-r border-slate-200 last:border-r-0">
                {date.split('-')[0]}
                <span className="block font-normal text-slate-400">{date.split('-')[1]}</span>
              </th>
            ))}
            <th className="px-4 py-3 font-semibold text-indigo-700 text-sm text-center bg-indigo-50 border-l border-slate-200">Total</th>
          </tr>
        </thead>
        <tbody className="divide-y divide-slate-100">
          {data.rows.map((row, idx) => (
            <tr key={`${row.member}-${row.project}-${idx}`} className="hover:bg-slate-50 transition-colors">
              <td className="px-4 py-3 font-medium text-slate-800 text-sm border-r border-slate-200 bg-white sticky left-0">
                <span className="inline-block px-2 py-1 rounded bg-slate-100 text-slate-600 font-mono text-xs">
                  {row.project}
                </span>
              </td>
              <td className="px-4 py-3 text-slate-700 text-sm border-r border-slate-200 bg-white sticky left-[120px] md:left-[140px]">
                <div className="flex items-center gap-2">
                  {row.avatar && (
                    <img 
                      src={row.avatar} 
                      alt={row.member} 
                      className="w-6 h-6 rounded-full border border-slate-200"
                      onError={(e) => (e.currentTarget.style.display = 'none')}
                    />
                  )}
                  <span className="truncate max-w-[150px]">{row.member}</span>
                </div>
              </td>
              {data.dates.map((date) => {
                const hours = row.dailyHours[date];
                return (
                  <td key={date} className={`px-2 py-3 text-xs text-center border-r border-slate-200 last:border-r-0 ${hours ? 'font-semibold text-slate-900' : 'text-slate-300'}`}>
                    {hours ? hours.toLocaleString(undefined, { minimumFractionDigits: 0, maximumFractionDigits: 2 }) : '-'}
                  </td>
                );
              })}
              <td className="px-4 py-3 font-bold text-indigo-600 text-sm text-center bg-indigo-50 border-l border-slate-200">
                {row.totalHours.toLocaleString(undefined, { minimumFractionDigits: 0, maximumFractionDigits: 2 })}
              </td>
            </tr>
          ))}
        </tbody>
        <tfoot>
          <tr className="bg-slate-100 font-bold">
            <td colSpan={2} className="px-4 py-3 text-sm text-slate-600 text-right border-r border-slate-200 sticky left-0 z-10 bg-slate-100">Daily Totals</td>
            {data.dates.map((date) => {
              const dailyTotal = data.rows.reduce((sum, row) => sum + (row.dailyHours[date] || 0), 0);
              return (
                <td key={date} className="px-2 py-3 text-xs text-center border-r border-slate-200 last:border-r-0 text-slate-700">
                  {dailyTotal ? dailyTotal.toLocaleString(undefined, { maximumFractionDigits: 1 }) : '-'}
                </td>
              );
            })}
            <td className="px-4 py-3 text-sm text-center text-indigo-800 bg-indigo-100 border-l border-slate-200">
              {data.rows.reduce((sum, row) => sum + row.totalHours, 0).toLocaleString(undefined, { maximumFractionDigits: 1 })}
            </td>
          </tr>
        </tfoot>
      </table>
    </div>
  );
};

export default TimesheetTable;

