interface MemberSummary {
  member: string;
  avatar?: string;
  dailyTotals: Record<string, number>;
  totalMonth: number;
}

const MemberSummaryTable: React.FC<Props> = ({ data }) => {
  const memberSummaries = useMemo(() => {
    const map: Record<string, MemberSummary> = {};

    data.rows.forEach((row) => {
      if (!map[row.member]) {
        map[row.member] = {
          member: row.member,
          avatar: row.avatar,
          dailyTotals: {},
          totalMonth: 0,
        };
      }

      Object.entries(row.dailyHours).forEach(([date, hours]) => {
        map[row.member].dailyTotals[date] = (map[row.member].dailyTotals[date] || 0) + hours;
        map[row.member].totalMonth += hours;
      });
    });

    return Object.values(map).sort((a, b) => a.member.localeCompare(b.member));
  }, [data]);

  if (data.rows.length === 0) return null;

  return (
    <div className="space-y-4">
      <div className="flex items-center gap-2">
        <div className="w-1 h-6 bg-indigo-600 rounded-full"></div>
