            </tr>
          </thead>
          <tbody className="divide-y divide-slate-100">
            {sortedRows.map((row, idx) => {
              const isTargetMet = row.memberTotalMonth >= targetHours;
              const statusColorClass = isTargetMet ? 'text-emerald-600' : 'text-rose-600';

              return (
                <tr key={`${row.member}-${row.project}-${idx}`} className="hover:bg-slate-50/50 transition-colors group">
